CREATE OR REPLACE VIEW vr_wef_hrb_by_day (membership_no, requestment_no, member_group_no, paid_date, total_receive, remark, operate_date, approve_date, wef_type, bank_acc_no, money_type_id, return_status, first_hrb_date) AS select sc_wef_req.membership_no,
       sc_wef_req.requestment_no,
       sc_mem_m_membership_registered.member_group_no,
       (select max(paid_date) FROM sc_fin_money_return where sc_wef_req.requestment_no = sc_fin_money_return.refno1) as paid_date,
       sc_wef_req.total_receive,
       sc_wef_req_hrb.remark,
       sc_wef_req.operate_date,
       sc_wef_req.approve_date,
       sc_wef_req.wef_type,
       sc_wef_req.bank_acc_no,
       sc_wef_req.money_type_id,
       sc_fin_money_return.return_status,
       sc_wef_req_hrb.first_hrb_date
from sc_wef_req,sc_wef_req_hrb,sc_fin_money_return,sc_mem_m_membership_registered
where sc_wef_req.requestment_no = sc_wef_req_hrb.requestment_no
and sc_mem_m_membership_registered.membership_no = sc_wef_req.membership_no
and sc_wef_req.requestment_no = sc_fin_money_return.refno1
and sc_fin_money_return.cancel_status = '0'
and sc_wef_req.cancel_status = '0'
and sc_wef_req.approve_status = '1'
and sc_wef_req.wef_type = 'HRB';

